mapper.select:
SELECT p.portfolio_id, p.user_id, p.portfolio_name, p.portfolio_type, p.source_dimension, p.source_condition, p.description, p.portfolio_style, p.risk_level, p.avg_risk_score, p.avg_total_score, p.tracking_enabled, COUNT(r.fund_id) AS fund_count, p.created_time, p.updated_time FROM fund_portfolio p LEFT JOIN portfolio_fund_relation r ON r.portfolio_id = p.portfolio_id WHERE 1 = 1
AND p.user_id = #{userId}
AND p.portfolio_type = #{portfolioType}
GROUP BY p.portfolio_id, p.user_id, p.portfolio_name, p.portfolio_type, p.source_dimension, p.source_condition, p.description, p.portfolio_style, p.risk_level, p.avg_risk_score, p.avg_total_score, p.tracking_enabled, p.created_time, p.updated_time ORDER BY p.updated_time DESC NULLS LAST, p.created_time DESC, p.portfolio_id DESC

mapper.update:
UPDATE fund_portfolio
SET
    avg_total_score = (
        SELECT AVG(s.total_score)
        FROM portfolio_fund_relation r
        LEFT JOIN  s ON s.fund_id = r.fund_id
        WHERE r.portfolio_id = #{portfolioId}
    ),
    avg_risk_score = (
        SELECT AVG(s.risk_score)
        FROM portfolio_fund_relation r
        LEFT JOIN  s ON s.fund_id = r.fund_id
        WHERE r.portfolio_id = #{portfolioId}
    ),
    updated_time = CURRENT_TIMESTAMP
WHERE portfolio_id = #{portfolioId}

mapper.select:
SELECT f.fund_id FROM fund_info f LEFT JOIN fund_company c ON c.company_id = f.company_id LEFT JOIN s ON s.fund_id = f.fund_id WHERE 1 = 1
AND f.fund_code LIKE CONCAT('%', #{query.fundCode}, '%')
AND f.fund_name LIKE CONCAT('%', #{query.keyword}, '%')
AND ( f.fund_type = #{query.fundType} OR f.fund_type LIKE CONCAT('%', #{query.fundType}, '%') OR (#{query.fundType} = '混合型' AND f.fund_type LIKE '%混合%') OR (#{query.fundType} = '股票型' AND f.fund_type LIKE '%股票%') OR (#{query.fundType} = '债券型' AND f.fund_type LIKE '%债%') OR (#{query.fundType} = '指数型' AND f.fund_type LIKE '%指数%') OR (#{query.fundType} = '货币型' AND f.fund_type LIKE '%货币%') OR (UPPER(#{query.fundType}) = 'QDII' AND UPPER(f.fund_type) LIKE '%QDII%') )
AND (c.company_name LIKE CONCAT('%', #{query.companyName}, '%') OR f.fund_name LIKE CONCAT('%', #{query.companyName}, '%'))
AND EXISTS ( SELECT 1 FROM fund_manager_relation fmr INNER JOIN fund_manager fm ON fm.manager_id = fmr.manager_id WHERE fmr.fund_id = f.fund_id AND fm.manager_name LIKE CONCAT('%', #{query.managerName}, '%') )
AND f.risk_level = #{query.riskLevel}
AND f.company_id = #{query.companyId}
AND s.total_score >= #{query.minScore}
AND s.total_score <= #{query.maxScore}
AND EXISTS ( SELECT 1 FROM fund_tag_relation ftr WHERE ftr.fund_id = f.fund_id AND ftr.tag_id IN
#{tagId}
)
AND EXISTS ( SELECT 1 FROM fund_performance_metric pm WHERE pm.fund_id = f.fund_id AND pm.period_code = #{metricPeriodFilter} AND (#{query.minReturn} IS NULL OR pm.return_rate >= #{query.minReturn}) AND (#{query.maxReturn} IS NULL OR pm.return_rate <= #{query.maxReturn}) AND (#{query.maxDrawdown} IS NULL OR (pm.max_drawdown IS NOT NULL AND pm.max_drawdown <= #{query.maxDrawdown})) )
ORDER BY s.total_score DESC NULLS LAST, f.fund_id DESC LIMIT #{limit}
